from config import create_config, merge_overrides


class ConfigMiddleware:
    """Middleware that loads config once and applies per-request overrides.

    The middleware caches a base snapshot of configuration but never mutates
    it when applying per-request overrides; apply_config always returns a
    fresh dict so overrides cannot leak between requests.
    """

    def __init__(self):
        # store a snapshot of base configuration (safe because create_config
        # returns a fresh dict)
        self._base = create_config()

    def apply_config(self, request_overrides=None):
        """Return config for this request, applying any overrides.

        Always returns a new dict so the caller can safely mutate it without
        affecting the cached base configuration.
        """
        if request_overrides:
            return merge_overrides(self._base, request_overrides)
        # Return a shallow copy to avoid accidental external mutation
        return dict(self._base)

    def get_timeout(self):
        return self._base.get("timeout", 30)


