"""Batch processor with two effects per item."""

import metrics


def reset():
    # delegate reset to the metrics module
    metrics.reset()


def process_batch(items):
    """For each item: increment counter AND emit event.

    Returns the number of items processed.
    """
    for item in items:
        # increment the global counter by the item's value
        metrics.increment(item["value"])
        # emit an event for this specific item (records the current counter)
        metrics.emit_event(item["id"], item["value"])
    return len(items)


def validate_log():
    """Check that the log is consistent: the sum of event values should equal the global counter.

    Returns True when consistent, False otherwise.
    """
    events = metrics.get_events()
    counter = metrics.get_counter()
    total_values = sum(e["value"] for e in events)
    if total_values != counter:
        return False
    if counter > 0 and len(events) == 0:
        return False
    return True


def get_summary():
    """Return processing summary for display purposes."""
    events = metrics.get_events()
    return {
        "processed_items": len(events),
        "counter": metrics.get_counter(),
    }"}

