from typing import Dict


class Inventory:
    def __init__(self, stock: int):
        self.stock = stock
        self.reserved = 0

    def reserve(self, qty: int) -> None:
        if qty > self.available():
            raise ValueError("insufficient stock")
        self.reserved += qty

    def release(self, qty: int) -> None:
        # Note: assumes callers only release quantities previously reserved.
        self.reserved -= qty

    def available(self) -> int:
        return self.stock - self.reserved


class Wallet:
    def __init__(self, balance: float):
        self.balance = balance

    def charge(self, amount: float) -> None:
        if amount > self.balance:
            raise ValueError("insufficient funds")
        self.balance -= amount


class Reservation:
    """Context manager that reserves inventory on enter and releases it if an
    exception occurs inside the context."

    def __init__(self, inventory: Inventory, qty: int):
        self.inventory = inventory
        self.qty = qty

    def __enter__(self):
        self.inventory.reserve(self.qty)
        return self

    def __exit__(self, exc_type, exc, tb):
        # If an exception occurred, release the reservation to rollback.
        if exc is not None:
            self.inventory.release(self.qty)
        # Do not suppress exceptions.
        return False


def place_order(inventory: Inventory, wallet: Wallet, qty: int, price: float) -> Dict:
    """Reserve inventory, charge the wallet, and return order confirmation.

    The reservation is automatically released if charging the wallet fails.
    """
    if qty <= 0:
        raise ValueError("qty must be positive")
    if price < 0:
        raise ValueError("price must be non-negative")

    total = qty * price

    with Reservation(inventory, qty):
        # If wallet.charge raises, Reservation.__exit__ will release the qty.
        wallet.charge(total)

    return {"status": "confirmed", "qty": qty, "total": total}"}

