{"reasoning":"Fixed a bug where raw statistics were computed from normalized data; refactored for clarity by adding type hints, clearer flow, and safer handling of empty inputs. compute_raw_stats now operates on the original input before normalization. Function docstrings and variable names were clarified.","code":"'''Metrics pipeline: compute raw stats before transforming data.

Refactored for clarity and to ensure raw stats reflect original input.
'''

from typing import Sequence, List, Dict, Any


def compute_raw_stats(data: Sequence[float]) -> Dict[str, float]:
    '''Compute statistics on raw (untransformed) data.

    Returns zeros when input is empty-ish (None or empty sequence).
    '''
    if not data:
        return {'raw_max': 0, 'raw_min': 0, 'raw_sum': 0}
    # Convert to a list so we can safely call min/max/sum without exhausting an iterator.
    nums = list(data)
    return {'raw_max': max(nums), 'raw_min': min(nums), 'raw_sum': sum(nums)}


def normalize(data: Sequence[float]) -> List[float]:
    '''Normalize data to 0-1 range.

    If all values are equal returns 0.5 for each element.
    Returns empty list for empty input.
    '''
    if not data:
        return []
    nums = list(data)
    lo, hi = min(nums), max(nums)
    if hi == lo:
        return [0.5] * len(nums)
    span = hi - lo
    return [(float(x) - lo) / span for x in nums]


def pipeline(data: Sequence[float]) -> Dict[str, Any]:
    '''Run pipeline: compute raw stats on original data, then normalize it.

    raw_stats MUST reflect the original data, not the normalized version.
    '''
    # Compute stats from the original data before any transformation.
    raw_stats = compute_raw_stats(data)
    cleaned = normalize(data)
    return {'raw_stats': raw_stats, 'cleaned': cleaned}


def format_report(result: Dict[str, Any]) -> str:
    '''Format pipeline result for display.'''
    raw_max = result.get('raw_stats', {}).get('raw_max', None)
    return f'max={raw_max}'
