from typing import Iterable, List, Dict, Any, Sequence


def compute_raw_stats(data: Sequence[float]) -> Dict[str, float]:
    '''Compute statistics on raw (untransformed) data.'''
    if not data:
        return {'raw_max': 0.0, 'raw_min': 0.0, 'raw_sum': 0.0}
    return {
        'raw_max': max(data),
        'raw_min': min(data),
        'raw_sum': sum(data),
    }


def normalize(data: Sequence[float]) -> List[float]:
    '''Normalize data to 0-1 range.'''
    if not data:
        return []
    lo, hi = min(data), max(data)
    if hi == lo:
        return [0.5] * len(data)
    return [(x - lo) / (hi - lo) for x in data]


def pipeline(data: Iterable[float]) -> Dict[str, Any]:
    '''Run pipeline: compute raw stats on the original data, then normalize.

    raw_stats MUST reflect the original data, not the normalized version.
    '''
    # Materialize the input so we can compute raw stats and then normalize
    original = list(data) if data is not None else []

