- Role names are normalized (lowercased/stripped) before lookup.
- Permission sets are immutable (frozenset) to avoid accidental mutation.
- A "moderator" role was added to fix the previously missing branch.
"""

from typing import FrozenSet, Dict

# Immutable empty permissions for unknown roles
_DEFAULT_PERMISSIONS: FrozenSet[str] = frozenset()

# Known role -> permission set mapping (values are frozenset for immutability)
ROLE_PERMISSIONS: Dict[str, FrozenSet[str]] = {
    "admin": frozenset({"read", "write", "delete", "manage_users"}),
    "moderator": frozenset({"read", "delete", "ban_users"}),
    "user": frozenset({"read", "write"}),
}


def get_permissions(role: str) -> FrozenSet[str]:
    """Return the (immutable) set of permissions for the given role.

    Role lookup is case-insensitive and ignores surrounding whitespace. Unknown
    roles return an empty frozenset instead of None.
    """
    if role is None:
        return _DEFAULT_PERMISSIONS
    key = str(role).strip().lower()
    return ROLE_PERMISSIONS.get(key, _DEFAULT_PERMISSIONS)


def has_permission(role: str, action: str) -> bool:
    """Check whether a role has a specific permission.

    Returns False if action is falsy or the role is unknown.
    """
    if not action:
        return False
    return action in get_permissions(role)


def get_known_roles() -> FrozenSet[str]:
    """Return the set of known role names."""
    return frozenset(ROLE_PERMISSIONS.keys())
